text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표 시점을 금요일 15:00 KST로 잡되, smoke test 통과를 전제로 한다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일 공개 릴리스를 목표로 한다.",
        "reason": "Doyun이 smoke test 통과 전 릴리스에 반대했으며 최종 결정으로 채택되지 않았다."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 수정한다.",
        "reason": "논의 후 거절되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 일정은 내부 스트레치 목표로만 언급되었고, 외부 공개 목표로 확정되지 않았다."
      },
      {
        "item": "README install steps는 가능하면 목요일까지 검토한다는 의견이 있었으나, 공식 담당자는 배정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README install steps가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
      }
    ],
    "non_decisions": [
      {
        "item": "README install steps 검토는 필요성이 언급되었지만 소유자와 확정 일정은 정해지지 않았다."
      },
      {
        "item": "Hara의 tarball 경로 확인은 Minjun의 smoke 결과 이후로 예정되었으나 정확한 마감 시점은 정해지지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "pending",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": "다음에는 smoke test 결과, tarball 경로, README install steps의 최신 상태, 그리고 최종 릴리스 승인 권한자를 확인하면 된다. 고객명, 예산, 보안 사고, 운영 장애, 법적 승인 요구사항, 추가 마감일은 이 메모에 없는 내용이므로 추측하거나 보완해서는 안 된다. 내부 수요일 스트레치 목표를 릴리스 노트에 넣을지는 아직 미결이므로, 확정 전에는 포함 여부를 단정하지 않는다.",
  "non_invention_rules": [
    "고객명은 없다.",
    "예산 정보는 없다.",
    "보안 사고는 언급되지 않았다.",
    "프로덕션 장애는 언급되지 않았다.",
    "법적 승인 요구사항은 언급되지 않았다.",
    "추가 owner는 배정되지 않은 항목에 대해 임의로 지정하지 않는다.",
    "추가 deadline은 명시되지 않은 경우 임의로 만들지 않는다.",
    "릴리스 승인 권한자와 릴리스 노트의 수요일 언급 여부는 미결 상태로 유지한다."
  ]
}
